package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetQuoteCharacter_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        Character quoteChar = format.getQuoteCharacter();
        assertNotNull(quoteChar);
        assertEquals('"', quoteChar.charValue());
    }

    @Test
    void testGetQuoteCharacter_CustomQuote() {
        CSVFormat format = CSVFormat.DEFAULT.withQuote('\'');
        Character quoteChar = format.getQuoteCharacter();
        assertNotNull(quoteChar);
        assertEquals('\'', quoteChar.charValue());
    }

    @Test
    void testGetQuoteCharacter_NullQuote() {
        CSVFormat format = CSVFormat.DEFAULT.withQuote((Character) null);
        Character quoteChar = format.getQuoteCharacter();
        assertNull(quoteChar);
    }

    @Test
    void testGetQuoteCharacter_UsingPredefinedFormats() {
        Character quoteChar;

        quoteChar = CSVFormat.EXCEL.getQuoteCharacter();
        assertNotNull(quoteChar);
        assertEquals('"', quoteChar.charValue());

        quoteChar = CSVFormat.INFORMIX_UNLOAD.getQuoteCharacter();
        assertNotNull(quoteChar);
        assertEquals('"', quoteChar.charValue());

        quoteChar = CSVFormat.INFORMIX_UNLOAD_CSV.getQuoteCharacter();
        assertNotNull(quoteChar);
        assertEquals('"', quoteChar.charValue());

        quoteChar = CSVFormat.MYSQL.getQuoteCharacter();
        assertNull(quoteChar);

        quoteChar = CSVFormat.POSTGRESQL_CSV.getQuoteCharacter();
        assertNotNull(quoteChar);
        assertEquals('"', quoteChar.charValue());

        quoteChar = CSVFormat.POSTGRESQL_TEXT.getQuoteCharacter();
        assertNotNull(quoteChar);
        assertEquals('"', quoteChar.charValue());

        quoteChar = CSVFormat.RFC4180.getQuoteCharacter();
        assertNotNull(quoteChar);
        assertEquals('"', quoteChar.charValue());

        quoteChar = CSVFormat.TDF.getQuoteCharacter();
        assertNotNull(quoteChar);
        assertEquals('"', quoteChar.charValue());
    }
}
